class Animal:
    def speak(self):
        print("동물이 소리를 낸다")

class Dog(Animal):
    def speak(self):
        print("멍멍!")

a = Animal()
d = Dog()
for animal in [a, d]:
    animal.speak()

class Animal:
    def __init__(self, name):
        self.name = name

class Dog(Animal):
    def __init__(self, name):
        super().__init__(name)

    def print_name(self):
        print(self.name)

d = Dog("바둑이")
d.print_name()

class Duck:
    def speak(self):
        print("꽥꽥!")

class Person:
    def speak(self):
        print("저는 오리 소리를 흉내낼 수 있어요, 꽥꽥!")

def make_it_speak(thing):
    thing.speak()

make_it_speak(Duck())
make_it_speak(Person())

class Animal:
    def speak(self):
        print("...")

    def greet(self):
        print("안녕! ", end="")
        self.speak()

class Dog(Animal):
    def speak(self):
        print("멍멍!")

d = Dog()
d.greet()
